async function saveAuthSession(session: AuthSession) { await SecureStore.setItemAsync(SECURE_AUTH_SESSION, JSON.stringify(session)); }
async function getStoredAuthSession(): Promise<AuthSession | null> { const raw = await SecureStore.getItemAsync(SECURE_AUTH_SESSION); if (!raw) return null; try { return JSON.parse(raw) as AuthSession; } catch { await SecureStore.deleteItemAsync(SECURE_AUTH_SESSION); return null; } }
async function clearAuthSession() { await SecureStore.deleteItemAsync(SECURE_AUTH_SESSION); }
function authHeaders(session: AuthSession) { return { Authorization: `Bearer ${session.accessToken}` }; }
async function apiRequest<T>(path: string, options: RequestInit = {}, session?: AuthSession, retry?: (session: AuthSession) => Promise<T>): Promise<T> { const response = await fetch(`${API_BASE_URL}${path}`, { ...options, headers: { 'Content-Type': 'application/json', ...(session ? authHeaders(session) : {}), ...(options.headers || {}) } }); if (response.status === 401 && retry && session) return retry(session); if (!response.ok) { let message = 'Request failed.'; try { const body = await response.json(); message = body.message || body.error || message; } catch {} throw new Error(message); } if (response.status === 204) return undefined as T; return response.json() as Promise<T>; }
async function authRequest(path: '/auth/signup' | '/auth/login', email: string, password: string, displayName?: string) { return apiRequest<AuthSession>(path, { method: 'POST', body: JSON.stringify({ email: email.trim().toLowerCase(), password, ...(displayName ? { displayName } : {}) }) }); }
function serverWinePayload(item: unknown): Wine | null { if (!item || typeof item !== 'object') return null; const record = item as { localPayload?: unknown; deletedAt?: string | null }; if (record.deletedAt) return null; const payload = record.localPayload; if (!payload || typeof payload !== 'object') return null; return withAutoDrinkWindow(normalizeWine(payload as Partial<Wine>)); }

function cleanLines(text: string) { return text.split(/\n+/).map((line) => line.replace(/[^\p{L}\p{N}&' .,-]/gu, '').replace(/\s+/g, ' ').trim()).filter((line) => line.length > 2); }
function firstHint(lines: string[], hints: string[]) { const joined = lines.join(' | '); return hints.find((hint) => new RegExp(`\\b${hint.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i').test(joined)) ?? ''; }

function styleFromText(text: string): WineStyle { if (/champagne|brut|prosecco|cava|sparkling/i.test(text)) return 'sparkling'; if (/rosé|rose|blush/i.test(text)) return 'rose'; if (/port|madeira|sherry|fortified/i.test(text)) return 'fortified'; if (/sauternes|tokaji|ice wine|dessert/i.test(text)) return 'dessert'; if (/orange|skin contact/i.test(text)) return 'orange'; if (/chardonnay|sauvignon|riesling|chablis|pinot grigio|chenin|white/i.test(text)) return 'white'; if (/cabernet|pinot noir|merlot|syrah|shiraz|malbec|grenache|nebbiolo|sangiovese|tempranillo|zinfandel|red|bordeaux|barolo|rioja/i.test(text)) return 'red'; return 'red'; }

function inferOriginFromText(text: string) { const value = text.toLowerCase(); const rules = [
  { country: 'France', regions: ['Bordeaux', 'Burgundy', 'Champagne', 'Rhône Valley', 'Loire Valley', 'Alsace', 'Provence'], terms: ['bordeaux', 'bourgogne', 'burgundy', 'champagne', 'chablis', 'sancerre', 'pouilly-fumé', 'côte de nuits', 'côte de beaune', 'rhône', 'loire', 'alsace', 'provence'] },
  { country: 'Italy', regions: ['Piedmont', 'Tuscany', 'Veneto', 'Sicily'], terms: ['barolo', 'barbaresco', 'piedmont', 'piemonte', 'toscana', 'tuscany', 'chianti', 'brunello', 'montalcino', 'bolgheri', 'veneto', 'amarone', 'sicilia', 'sicily'] },
  { country: 'Spain', regions: ['Rioja', 'Ribera del Duero', 'Priorat'], terms: ['rioja', 'ribera del duero', 'priorat', 'rías baixas', 'rias baixas'] },
  { country: 'United States', regions: ['California', 'Oregon', 'Washington'], terms: ['napa', 'sonoma', 'paso robles', 'santa barbara', 'willamette', 'columbia valley', 'oregon', 'california'] },
  { country: 'Argentina', regions: ['Mendoza', 'Salta'], terms: ['mendoza', 'uco valley', 'salta'] },
  { country: 'Chile', regions: ['Maipo Valley', 'Colchagua Valley'], terms: ['maipo', 'colchagua', 'aconcagua', 'casablanca valley'] },
  { country: 'Australia', regions: ['South Australia', 'Victoria', 'Western Australia'], terms: ['barossa', 'coonawarra', 'mclaren vale', 'yarra', 'margaret river'] },
  { country: 'New Zealand', regions: ['Marlborough', 'Central Otago'], terms: ['marlborough', 'central otago', 'hawke'] },
  { country: 'Germany', regions: ['Mosel', 'Rheingau', 'Pfalz'], terms: ['mosel', 'rheingau', 'pfalz', 'nahe'] },
  { country: 'Portugal', regions: ['Douro', 'Vinho Verde', 'Madeira'], terms: ['douro', 'vinho verde', 'madeira', 'alentejo'] }
];
  const found = rules.find((rule) => rule.terms.some((term) => value.includes(term)));
  return found ? { country: found.country, region: found.regions.find((region) => value.includes(region.toLowerCase())) || '' } : { country: '', region: '' }; }
function originSummary(wine: Partial<Wine>) { return [wine.appellation, wine.subRegion, wine.region].filter(Boolean).join(' · '); }

function countryCode(country?: string) { const normalized = (country || '').toLowerCase(); const codes: Record<string, string> = { france: 'FR', italy: 'IT', spain: 'ES', 'united states': 'US', usa: 'US', argentina: 'AR', chile: 'CL', australia: 'AU', 'new zealand': 'NZ', germany: 'DE', portugal: 'PT', austria: 'AT', greece: 'GR', 'south africa': 'ZA' }; return codes[normalized] || 'OR'; }
function chipLabel(value: string) { const labels: Record<string, string> = { all: 'All', cellar: 'In Cellar', consumed: 'Consumed', wishlist: 'Wishlist', 'drink now': 'Drink Now', rated: 'Rated' }; return labels[value] || value; }
function countryLabel(wine: Partial<Wine>) { return wine.country ? `${countryCode(wine.country)} · ${wine.country}` : ''; }
function professionalNote(wine: Partial<Wine>) { const text = `${wine.style} ${wine.varietal} ${wine.region}`.toLowerCase(); if (/cabernet|bordeaux|malbec/.test(text)) return 'Professional profile: blackcurrant, plum, cedar, graphite, firm tannins, and a structured finish.'; if (/pinot|burgundy/.test(text)) return 'Professional profile: red cherry, raspberry, rose petal, forest floor, fine tannins, and bright acidity.'; if (/nebbiolo|barolo|barbaresco/.test(text)) return 'Professional profile: sour cherry, rose, tar, licorice, orange peel, high acidity, and grippy tannins.'; if (/chardonnay|chablis/.test(text)) return 'Professional profile: lemon curd, apple, chalk, light oak or lees texture, and a crisp mineral finish.'; if (/sauvignon|sancerre/.test(text)) return 'Professional profile: grapefruit, lime, gooseberry, fresh herbs, and brisk acidity.'; if (/riesling|mosel/.test(text)) return 'Professional profile: lime, peach, petrol, slate, and vivid acidity with a precise finish.'; if (/sparkling|champagne|brut/.test(text)) return 'Professional profile: green apple, citrus, brioche, almond, fine mousse, and a clean mineral finish.'; if (/rose|rosé/.test(text)) return 'Professional profile: strawberry, watermelon rind, citrus zest, florals, and a dry refreshing finish.'; return 'Professional profile: balanced fruit, savory detail, fresh acidity, and a food-friendly finish.'; }
function enrichedFromHeuristics(extracted: Partial<Wine>): Partial<Wine> { const base = { ...emptyWine, ...extracted }; const style = base.style !== 'unknown' ? base.style : styleFromText(`${base.wineName} ${base.producer} ${base.region} ${base.varietal} ${base.rawText}`); const inferred = inferOriginFromText(`${base.wineName} ${base.producer} ${base.region} ${base.rawText}`); const draft = { ...base, style, country: base.country || inferred.country, region: base.region || inferred.region }; const pairings = pairingFor(draft); const withWindow = withAutoDrinkWindow(draft); return { ...extracted, country: draft.country, region: draft.region, style, notes: extracted.notes || professionalNote(draft), foodPairings: pairings.join(', '), drinkStart: withWindow.drinkStart, drinkEnd: withWindow.drinkEnd, dataSource: extracted.dataSource || (WINE_SEARCHER_API_KEY ? 'Cellar estimate. Wine-Searcher returned no exact match.' : 'Cellar estimate. Add EXPO_PUBLIC_WINE_SEARCHER_API_KEY for live Wine-Searcher data.') }; }
function pickApiValue(record: Record<string, unknown>, keys: string[]) { for (const key of keys) { const value = record[key]; if (value !== undefined && value !== null && String(value).trim()) return String(value); } return ''; }
async function searchWineDatabase(query: string): Promise<Partial<Wine>[]> { const fallbackSeed = enrichedFromHeuristics({ wineName: query, rawText: query }); if (!query.trim()) return []; if (!WINE_SEARCHER_API_KEY) return [fallbackSeed, ...['Burgundy Pinot Noir', 'Champagne Brut Reserve', 'Napa Cabernet Sauvignon'].filter((x) => !query.toLowerCase().includes(x.toLowerCase())).slice(0, 2).map((name) => enrichedFromHeuristics({ wineName: name, rawText: `${query} ${name}`, status: 'wishlist' }))]; const params = new URLSearchParams({ api_key: WINE_SEARCHER_API_KEY, winename: query.trim(), vintage: 'NV', currencycode: 'USD', location: 'USA' }); const response = await fetch(`${WINE_SEARCHER_BASE_URL}?${params.toString()}`); if (!response.ok) throw new Error('Wine database search failed.'); const json = await response.json() as { results?: unknown[]; wines?: unknown[] }; const records: unknown[] = Array.isArray(json) ? json : Array.isArray(json.results) ? json.results : Array.isArray(json.wines) ? json.wines : [json]; const mapped = records.filter((item: unknown) => item && typeof item === 'object').slice(0, 8).map((record) => { const r = record as Record<string, unknown>; const base = enrichedFromHeuristics({ wineName: pickApiValue(r, ['wine_name', 'wine-name', 'name', 'product-name']) || query, producer: pickApiValue(r, ['producer', 'winery']), vintage: pickApiValue(r, ['vintage']), country: pickApiValue(r, ['country', 'country_name', 'origin_country']), region: pickApiValue(r, ['region', 'region_name', 'state']), subRegion: pickApiValue(r, ['sub_region', 'sub-region', 'subregion', 'district', 'province']), appellation: pickApiValue(r, ['appellation', 'ava', 'aoc', 'doc', 'docg', 'designation']), varietal: pickApiValue(r, ['grape', 'varietal', 'variety']), marketValue: pickApiValue(r, ['price-average', 'price_average', 'average_price', 'avg_price', 'market_value', 'market-value', 'value']), criticScore: pickApiValue(r, ['score', 'critic-score', 'critic_score', 'rating']), dataSource: 'Wine-Searcher API', rawText: query }); return { ...base, status: 'wishlist' as WineStatus }; }); return mapped.length ? mapped : [fallbackSeed]; }
async function lookupWineData(extracted: Partial<Wine>): Promise<Partial<Wine>> { const fallback = enrichedFromHeuristics(extracted); if (!WINE_SEARCHER_API_KEY) return fallback; const winename = [extracted.producer, extracted.wineName, extracted.region].filter(Boolean).join(' ').trim() || extracted.rawText || ''; if (!winename) return fallback; const params = new URLSearchParams({ api_key: WINE_SEARCHER_API_KEY, winename, vintage: extracted.vintage || 'NV', currencycode: 'USD', location: 'USA' }); const response = await fetch(`${WINE_SEARCHER_BASE_URL}?${params.toString()}`); if (!response.ok) throw new Error('Wine database lookup failed.'); const json = await response.json() as { results?: unknown[]; wines?: unknown[] }; const records: unknown[] = Array.isArray(json) ? json : Array.isArray(json.results) ? json.results : Array.isArray(json.wines) ? json.wines : [json]; const record = records.find((item: unknown) => item && typeof item === 'object') as Record<string, unknown> | undefined; if (!record) return fallback; const fullFallback: Wine = { ...emptyWine, ...fallback }; const apiWine: Wine = { ...fullFallback, wineName: pickApiValue(record, ['wine_name', 'wine-name', 'name', 'product-name']) || fullFallback.wineName, producer: pickApiValue(record, ['producer', 'winery']) || fullFallback.producer, vintage: pickApiValue(record, ['vintage']) || fullFallback.vintage, country: pickApiValue(record, ['country', 'country_name', 'origin_country']) || fullFallback.country, region: pickApiValue(record, ['region', 'region_name', 'state']) || fullFallback.region, subRegion: pickApiValue(record, ['sub_region', 'sub-region', 'subregion', 'district', 'province']) || fullFallback.subRegion, appellation: pickApiValue(record, ['appellation', 'ava', 'aoc', 'doc', 'docg', 'designation']) || fullFallback.appellation, varietal: pickApiValue(record, ['grape', 'varietal', 'variety']) || fullFallback.varietal, marketValue: pickApiValue(record, ['price-average', 'price_average', 'average_price', 'avg_price', 'market_value', 'market-value', 'value']) || fullFallback.marketValue, price: fullFallback.price, drinkStart: yearOnly(databaseDrinkStart(record)) || fullFallback.drinkStart, drinkEnd: yearOnly(databaseDrinkEnd(record)) || fullFallback.drinkEnd, criticScore: pickApiValue(record, ['score', 'critic-score', 'critic_score', 'rating']) || fullFallback.criticScore, dataSource: 'Wine-Searcher API' }; const inferred = inferOriginFromText(`${apiWine.wineName} ${apiWine.producer} ${apiWine.appellation} ${apiWine.subRegion} ${apiWine.region} ${apiWine.varietal}`); const withOrigin: Wine = { ...apiWine, country: apiWine.country || inferred.country, region: apiWine.region || inferred.region }; const withStyle: Wine = { ...withOrigin, style: styleFromText(`${withOrigin.wineName} ${withOrigin.country} ${withOrigin.region} ${withOrigin.varietal}`) }; const withWindow = withAutoDrinkWindow(withStyle); return { ...withWindow, notes: professionalNote(withWindow), foodPairings: pairingFor(withWindow).join(', ') }; }

function parseWineLabel(text: string) { const lines = cleanLines(text); const vintage = lines.join(' ').match(/\b(19[5-9]\d|20[0-3]\d)\b/)?.[0] ?? ''; const region = firstHint(lines, REGION_HINTS); const varietal = firstHint(lines, GRAPE_HINTS); const producer = lines.find((line) => !/^\d{4}$/.test(line) && !line.includes('%')) ?? ''; const skip = new Set([producer.toLowerCase(), vintage.toLowerCase(), region.toLowerCase(), varietal.toLowerCase()]); const wineName = lines.slice(1).find((line) => !skip.has(line.toLowerCase()) && !/^\d{4}$/.test(line) && !/alcohol|volume|contains|government|warning/i.test(line)) ?? producer; return { wineName, producer, vintage, region, varietal, rawText: text }; }
function includesWine(wine: Wine, query: string) { const haystack = [wine.wineName, wine.producer, wine.vintage, wine.country, wine.region, wine.subRegion, wine.appellation, wine.varietal, wine.notes, wine.tags, wine.purchaseSource, wine.location, wine.bottleSize].join(' ').toLowerCase(); return haystack.includes(query.toLowerCase()); }
function money(value: string) { const parsed = Number(String(value).replace(/[^0-9.]/g, '')); return Number.isFinite(parsed) ? parsed : 0; }
function formatCurrency(value: string | number) { const parsed = typeof value === 'number' ? value : money(value); return parsed ? `$${Math.round(parsed).toLocaleString('en-US')}` : '—'; }
function normalizeWine(wine: Partial<Wine>): Wine { const rawStatus = String(wine.status || 'cellar'); const status = rawStatus === 'opened' ? 'consumed' : rawStatus; return { ...emptyWine, ...wine, status: (status === 'consumed' || status === 'wishlist' || status === 'cellar') ? status : 'cellar' } as Wine; }
function styleOrder(style: WineStyle | string) { const order = ['sparkling', 'white', 'rose', 'orange', 'red', 'dessert', 'fortified', 'unknown']; const index = order.indexOf(style); return index < 0 ? 99 : index; }
function estimatedWindowYears(wine: Wine) { const text = `${wine.style} ${wine.varietal} ${wine.region}`; if (/cabernet|nebbiolo|barolo|bordeaux|syrah|shiraz|tempranillo/i.test(text)) return [6, 16]; if (/riesling|champagne|brut/i.test(text)) return [2, 10]; if (/chardonnay|chablis|sauvignon|white/i.test(text)) return [1, 6]; if (/dessert|sauternes|port|fortified/i.test(text)) return [5, 30]; return [2, 9]; }
function databaseDrinkStart(record: Record<string, unknown>) { return pickApiValue(record, ['drink_from', 'drink-from', 'drinking_from', 'drinking-from', 'drink_start', 'drink-start', 'drink_start_year', 'window_start', 'window-start', 'best_from', 'best-from', 'begin_consume', 'begin-consume', 'maturity_start', 'maturity-start', 'maturity_from', 'maturity-from']); }
function databaseDrinkEnd(record: Record<string, unknown>) { return pickApiValue(record, ['drink_to', 'drink-to', 'drinking_to', 'drinking-to', 'drink_end', 'drink-end', 'drink_end_year', 'window_end', 'window-end', 'best_to', 'best-to', 'drink_by', 'drink-by', 'end_consume', 'end-consume', 'maturity_end', 'maturity-end', 'maturity_to', 'maturity-to']); }
function yearOnly(value: string | number) { const match = String(value || '').match(/(19[5-9]\d|20[0-5]\d)/); return match?.[0] || ''; }
function withAutoDrinkWindow(wine: Wine): Wine { const vintage = Number(wine.vintage); const existingStart = yearOnly(wine.drinkStart); const existingEnd = yearOnly(wine.drinkEnd); if (!vintage) return { ...wine, drinkStart: existingStart, drinkEnd: existingEnd }; const [offsetStart, offsetEnd] = estimatedWindowYears(wine); return { ...wine, drinkStart: existingStart || String(vintage + offsetStart), drinkEnd: existingEnd || String(vintage + offsetEnd) }; }
function drinkingWindow(wine: Wine) { const vintage = Number(wine.vintage); const manualStart = Number(wine.drinkStart); const manualEnd = Number(wine.drinkEnd); if (!vintage && !(manualStart || manualEnd)) return { label: 'No window yet', detail: 'Add a vintage or drinking window and Cellar will tell you when to open it.', start: '', end: '' }; const [offsetStart, offsetEnd] = estimatedWindowYears(wine); const start = manualStart || (vintage ? vintage + offsetStart : 0); const end = manualEnd || (vintage ? vintage + offsetEnd : 0); const year = new Date().getFullYear(); if (start && year < start) return { label: 'Hold', detail: `Best guess: start checking around ${start}.`, start, end }; if (end && year <= end) return { label: 'Drink now', detail: `Likely in a good window through ${end}.`, start, end }; return { label: 'Past peak?', detail: 'Open soon unless you know this bottle has the structure to keep going.', start, end }; }
function pairingFor(wine: Wine) { const text = `${wine.style} ${wine.varietal} ${wine.region}`.toLowerCase(); if (/cabernet|bordeaux|malbec|syrah|shiraz|nebbiolo|barolo/.test(text)) return ['ribeye or lamb', 'mushroom ragù', 'aged cheddar']; if (/pinot|burgundy|gamay/.test(text)) return ['roast chicken', 'salmon', 'duck or mushrooms']; if (/chardonnay|chablis/.test(text)) return ['lobster or crab', 'roast chicken', 'triple-cream cheese']; if (/sauvignon|riesling|gewürz|white/.test(text)) return ['thai or vietnamese', 'goat cheese', 'spring vegetables']; if (/sparkling|champagne|brut/.test(text)) return ['oysters', 'caviar service', 'tempura']; if (/rose|rosé/.test(text)) return ['tuna crudo', 'summer salads', 'grilled shrimp']; return ['charcuterie', 'roast vegetables', 'aged cheeses, olive tapenade']; }
function sommelierNote(wine: Wine) { const window = drinkingWindow(wine); const pairings = pairingFor(wine).slice(0, 2).join(' or '); const grape = wine.varietal || wine.style; return `${grape || 'This bottle'} wants ${pairings}. ${window.label === 'Drink now' ? 'This is a good candidate for the next dinner.' : window.detail}`; }

export default function App() {
  const [wines, setWines] = useState<Wine[]>([]);
  const [draft, setDraft] = useState<Wine>(emptyWine);
  const [profile, setProfile] = useState<Profile>(defaultProfile);
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [tab, setTab] = useState<Tab>('collection');
  const [selectedId, setSelectedId] = useState('');
  const [query, setQuery] = useState('');
  const [discoverQuery, setDiscoverQuery] = useState('');
  const [discoverResults, setDiscoverResults] = useState<Wine[]>([]);
  const [filter, setFilter] = useState<string>('all');
  const [layout, setLayout] = useState<Layout>('grid');
  const [discoverLayout, setDiscoverLayout] = useState<Layout>('list');
  const [status, setStatus] = useState('Ready for the next bottle.');
  const [busy, setBusy] = useState(false);
  const [auth, setAuth] = useState<AuthSession | null>(null);
  const [authReady, setAuthReady] = useState(false);
  const [syncState, setSyncState] = useState<SyncState>('local');
  const [syncMessage, setSyncMessage] = useState('Local-only mode. Sign in to back up and sync.');
  const [lastSyncAt, setLastSyncAt] = useState('');
  const syncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const fade = useRef(new Animated.Value(1)).current;
  const rise = useRef(new Animated.Value(0)).current;

  useEffect(() => { void bootstrap(); }, []);
  useEffect(() => { void AsyncStorage.setItem(STORAGE_WINES, JSON.stringify(wines)); }, [wines]);
  useEffect(() => { if (!authReady || !auth) return; if (syncTimer.current) clearTimeout(syncTimer.current); syncTimer.current = setTimeout(() => { void syncCellar('auto'); }, 1200); return () => { if (syncTimer.current) clearTimeout(syncTimer.current); }; }, [wines, authReady, auth]);
  useEffect(() => {
    fade.setValue(0);
    rise.setValue(10);
    Animated.parallel([
      Animated.timing(fade, { toValue: 1, duration: 220, useNativeDriver: true }),
      Animated.spring(rise, { toValue: 0, damping: 18, stiffness: 160, useNativeDriver: true }),
    ]).start();
  }, [fade, rise, tab]);

  async function bootstrap() { const [storedWines, storedProfile, onboarded, storedView, storedAuth] = await Promise.all([AsyncStorage.getItem(STORAGE_WINES), AsyncStorage.getItem(STORAGE_PROFILE), AsyncStorage.getItem(STORAGE_ONBOARDED), AsyncStorage.getItem(STORAGE_VIEW), getStoredAuthSession()]); if (storedWines) setWines(JSON.parse(storedWines).map(normalizeWine)); if (storedProfile) setProfile({ ...defaultProfile, ...JSON.parse(storedProfile) }); if (storedView === 'grid' || storedView === 'list') { setLayout(storedView); setDiscoverLayout(storedView); } if (storedAuth) { setAuth(storedAuth); setSyncState('synced'); setSyncMessage(`Signed in as ${storedAuth.user.email}. Sync will run automatically.`); } setAuthReady(true); setShowOnboarding(onboarded !== 'yes'); }

  const ownedWines = useMemo(() => wines.filter((wine) => wine.status === 'cellar'), [wines]);
  const consumedWines = useMemo(() => wines.filter((wine) => wine.status === 'consumed'), [wines]);
  const filtered = useMemo(() => wines.filter((wine) => (((filter === 'all' && wine.status !== 'wishlist') || filter === wine.status || (filter === wine.style && wine.status === 'cellar') || (filter === 'rated' && wine.rating >= 4 && wine.status === 'cellar') || (filter === 'drink now' && wine.status === 'cellar' && drinkingWindow(wine).label === 'Drink now'))) && (!query.trim() || includesWine(wine, query.trim()))), [wines, filter, query]);
  const displayWines = useMemo(() => [...filtered].sort((a, b) => styleOrder(a.style) - styleOrder(b.style) || (a.wineName || '').localeCompare(b.wineName || '')), [filtered]);
  const cellarValue = useMemo(() => ownedWines.reduce((sum, wine) => sum + (money(wine.marketValue || wine.price) || 0), 0), [ownedWines]);
  const drinkNowCount = useMemo(() => ownedWines.filter((wine) => drinkingWindow(wine).label === 'Drink now').length, [ownedWines]);
  const selected = useMemo(() => wines.find((wine) => wine.id === selectedId) ?? wines[0], [wines, selectedId]);
  const collectionFilters = useMemo(() => ['all', 'cellar', 'consumed', 'drink now', 'rated', 'wishlist', ...styles], []);
  const openWine = useCallback((id: string) => { setSelectedId(id); setTab('detail'); }, []);
  const setViewPreference = useCallback((next: Layout) => { setLayout(next); setDiscoverLayout(next); AsyncStorage.setItem(STORAGE_VIEW, next).catch(() => {}); }, []);
  const renderWineItem = useCallback(({ item }: { item: Wine }) => <WineCard wine={item} layout={layout} onOpen={openWine} />, [layout, openWine]);
  const insights = useMemo(() => { const rated = ownedWines.filter((wine) => wine.rating > 0); const average = rated.length ? rated.reduce((sum, wine) => sum + wine.rating, 0) / rated.length : 0; const count = (key: keyof Wine) => ownedWines.reduce<Record<string, number>>((acc, wine) => { const value = String(wine[key] || 'Unknown'); acc[value] = (acc[value] ?? 0) + 1; return acc; }, {}); return { average, varietals: Object.entries(count('varietal')).sort((a, b) => b[1] - a[1]).slice(0, 5), styles: Object.entries(count('style')).sort((a, b) => styleOrder(a[0]) - styleOrder(b[0])) }; }, [ownedWines]);

  async function refreshAuthSession(current = auth) {
    if (!current) throw new Error('Sign in required.');
    const next = await apiRequest<AuthSession>('/auth/refresh', { method: 'POST', body: JSON.stringify({ refreshToken: current.refreshToken }) });
    await saveAuthSession(next);
    setAuth(next);
    return next;
  }

  async function requestWithRefresh<T>(path: string, options: RequestInit = {}, session = auth): Promise<T> {
    if (!session) throw new Error('Sign in required.');
    return apiRequest<T>(path, options, session, async () => apiRequest<T>(path, options, await refreshAuthSession(session)));
  }

  async function handleAuth(mode: 'login' | 'signup', email: string, password: string, displayName?: string) {
    setBusy(true); setSyncState('syncing'); setSyncMessage(mode === 'signup' ? 'Creating secure backup account.' : 'Signing in.');
    try {
      const session = await authRequest(mode === 'signup' ? '/auth/signup' : '/auth/login', email, password, displayName);
      await saveAuthSession(session);
      setAuth(session);
      setSyncMessage('Signed in. Backing up this device now.');
      await syncCellar('manual', session);
      setStatus('Signed in. Cellar backup is enabled.');
    } catch (error) { const message = error instanceof Error ? error.message : 'Authentication failed.'; setSyncState('error'); setSyncMessage(message); Alert.alert(mode === 'signup' ? 'Signup failed' : 'Login failed', message); }
    finally { setBusy(false); }
  }

  async function logout() {
    const current = auth;
    setAuth(null); setSyncState('local'); setSyncMessage('Local-only mode. This device keeps working offline.'); setLastSyncAt('');
    await clearAuthSession();
    if (current) apiRequest('/auth/logout', { method: 'POST', body: JSON.stringify({ refreshToken: current.refreshToken }) }).catch(() => {});
  }

  async function syncCellar(mode: 'auto' | 'manual' = 'manual', sessionOverride?: AuthSession | null) {
    const session = sessionOverride ?? auth;
    if (!session) { setSyncState('local'); setSyncMessage('Local-only mode. Sign in to back up and sync.'); return; }
    setSyncState('syncing');
    if (mode === 'manual') setSyncMessage('Syncing this cellar with your cloud backup.');
    try {
      const changes = wines.map((wine) => ({ clientId: wine.id, operation: 'upsert' as const, entityType: 'cellar_bottle' as const, payload: wine, updatedAt: wine.dateAdded || new Date().toISOString() }));
      await requestWithRefresh('/sync/push', { method: 'POST', body: JSON.stringify({ changes }) }, session);
      const snapshot = await requestWithRefresh<{ bottles?: unknown[] }>('/sync/snapshot', { method: 'GET' }, session);
      const remoteWines = (snapshot.bottles || []).map(serverWinePayload).filter((wine): wine is Wine => Boolean(wine));
      if (remoteWines.length) setWines((current) => {
        const merged = new Map<string, Wine>();
        [...remoteWines, ...current].forEach((wine) => merged.set(wine.id, wine));
        const next = Array.from(merged.values());
        return JSON.stringify(next) === JSON.stringify(current) ? current : next;
      });
      const stamp = new Date().toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
      setLastSyncAt(stamp); setSyncState('synced'); setSyncMessage(`Synced ${wines.length} bottles at ${stamp}.`);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Sync failed. Local data is safe.';
      setSyncState('offline'); setSyncMessage(`${message} Changes remain saved on this device.`);
      if (mode === 'manual') Alert.alert('Sync paused', `${message}\n\nYour cellar is still saved locally and will sync when the connection works again.`);
    }
  }

  async function pickImage(source: 'camera' | 'library') {
    setBusy(true); setTab('add'); setStatus('Reading the label and preparing cellar details.');
    try {
      const permission = source === 'camera' ? await ImagePicker.requestCameraPermissionsAsync() : await ImagePicker.requestMediaLibraryPermissionsAsync();
      if (!permission.granted) { Alert.alert(source === 'camera' ? 'Camera permission needed' : 'Photo permission needed', 'Enable access to add label photos to your cellar.'); return; }
      const result = source === 'camera' ? await ImagePicker.launchCameraAsync({ quality: 0.88, allowsEditing: true }) : await ImagePicker.launchImageLibraryAsync({ quality: 0.88, allowsEditing: true });
      if (result.canceled) return;
      const uri = result.assets[0].uri;
      let rawText = '';
      try {
        const ocr = await import('expo-text-extractor');
        if (ocr.isSupported) rawText = (await ocr.extractTextFromImage(uri)).join('\n');
      } catch { rawText = ''; }
      const extracted = rawText ? parseWineLabel(rawText) : { wineName: '', producer: '', vintage: '', region: '', country: '', subRegion: '', appellation: '', varietal: '', rawText: 'OCR needs a development/TestFlight build. Expo Go can save the image and manual fields.' };
      setStatus(rawText ? 'Label read. Checking the wine database now.' : 'Photo attached. For real OCR, use a dev build or TestFlight build.');
      const enriched = await lookupWineData(extracted).catch(() => enrichedFromHeuristics(extracted));
      setDraft(withAutoDrinkWindow({ ...emptyWine, ...enriched, photo: uri }));
      setStatus(rawText ? 'Matched and enriched. Review the cellar profile before saving.' : 'Photo attached. Manual fields are ready.');
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    } catch (error) { setStatus(error instanceof Error ? error.message : 'Could not read that image.'); }
    finally { setBusy(false); }
  }

  async function runDiscoverSearch() { setBusy(true); setStatus('Searching the wine database.'); try { const results = await searchWineDatabase(discoverQuery); setDiscoverResults(results.map((wine, index) => ({ ...emptyWine, ...wine, id: `discover-${Date.now()}-${index}`, status: 'wishlist' }))); setStatus(results.length ? 'Discovery results ready. Save anything interesting to the wishlist.' : 'No wine matches found yet.'); } catch (error) { setStatus(error instanceof Error ? error.message : 'Search failed.'); } finally { setBusy(false); } }
  function saveWishlist(wine: Wine) { const wish = withAutoDrinkWindow({ ...wine, id: String(Date.now()), status: 'wishlist' as WineStatus, dateAdded: new Date().toISOString(), photo: '' }); setWines((current) => [wish, ...current]); setStatus('Saved to wishlist. Not counted as cellar inventory.'); Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); }
  function saveWine() { const wine = withAutoDrinkWindow({ ...draft, id: draft.id || String(Date.now()), wineName: draft.wineName.trim() || 'Untitled bottle', dateAdded: draft.dateAdded || new Date().toISOString(), dateConsumed: draft.status === 'consumed' && !draft.dateConsumed ? new Date().toISOString().slice(0, 10) : draft.dateConsumed }); setWines((current) => [wine, ...current.filter((item) => item.id !== wine.id)]); setDraft(emptyWine); setTab('collection'); setStatus('Saved to your private cellar.'); Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); }
  function updateWine(next: Wine) { const withWindow = withAutoDrinkWindow({ ...next, dateConsumed: next.status === 'consumed' && !next.dateConsumed ? new Date().toISOString().slice(0, 10) : next.dateConsumed }); setWines((current) => current.map((wine) => wine.id === next.id ? withWindow : wine)); }
  function deleteWine(id: string) { Alert.alert('Delete bottle?', 'This removes it from this device.', [{ text: 'Cancel', style: 'cancel' }, { text: 'Delete', style: 'destructive', onPress: () => { setWines((current) => current.filter((wine) => wine.id !== id)); setTab('collection'); } }]); }
  async function exportJson() { const path = `${FileSystem.cacheDirectory}wine-cellar-${new Date().toISOString().slice(0, 10)}.json`; await FileSystem.writeAsStringAsync(path, JSON.stringify(wines, null, 2)); if (await Sharing.isAvailableAsync()) await Sharing.shareAsync(path); }
  async function importJson() { const picked = await DocumentPicker.getDocumentAsync({ type: 'application/json', copyToCacheDirectory: true }); if (picked.canceled) return; const text = await FileSystem.readAsStringAsync(picked.assets[0].uri); const incoming = JSON.parse(text); if (!Array.isArray(incoming)) throw new Error('Import file was not a wine list.'); setWines((current) => [...incoming.map((wine) => withAutoDrinkWindow(normalizeWine({ ...wine, id: wine.id || `${Date.now()}-${Math.random()}` }))), ...current]); setStatus(`Imported ${incoming.length} bottles.`); }
  function addSamples() { setWines([{ ...emptyWine, id: 'sample-1', wineName: 'Estate Cabernet Sauvignon', producer: 'Stag Ridge', vintage: '2019', region: 'Napa Valley', country: 'United States', subRegion: 'California', appellation: 'Napa Valley AVA', varietal: 'Cabernet Sauvignon', rating: 4.5, style: 'red', status: 'cellar', price: '68', marketValue: '92', location: 'Rack A / Shelf 2', drinkStart: '2025', drinkEnd: '2035', tags: 'organic, steak night', notes: 'Blackcurrant, cedar, graphite, and polished tannin.', dateConsumed: '', bottleSize: '750ml', dateAdded: new Date().toISOString() }, { ...emptyWine, id: 'sample-2', wineName: 'Premier Cru Chablis', producer: 'Domaine des Lunes', vintage: '2021', region: 'Burgundy', country: 'France', subRegion: 'Chablis', appellation: 'Chablis Premier Cru', varietal: 'Chardonnay', rating: 4, style: 'white', status: 'consumed', price: '54', marketValue: '61', location: 'Wine fridge / Top shelf', drinkStart: '2023', drinkEnd: '2028', tags: 'sustainable, seafood', notes: 'Lemon peel, oyster shell, precise, mineral, and elegant.', dateConsumed: new Date().toISOString().slice(0, 10), bottleSize: '750ml', dateAdded: new Date().toISOString() }, { ...emptyWine, id: 'sample-3', wineName: 'Brut Reserve', producer: 'Maison Aster', vintage: '2018', region: 'Champagne', country: 'France', subRegion: 'Montagne de Reims', appellation: 'Champagne AOC', varietal: 'Pinot Noir / Chardonnay', rating: 0, style: 'sparkling', status: 'wishlist', price: '82', purchaseSource: 'K&L Wines', tags: 'wishlist, celebration', notes: 'Reserved for a future celebration.', dateConsumed: '', bottleSize: '750ml', dateAdded: new Date().toISOString() }, ...wines]); }

  const heroBlock = <Animated.View style={{ opacity: fade, transform: [{ translateY: rise }] }}><View style={s.hero}><Text style={s.eyebrow}>{profile.name ? `${profile.name}'s cellar` : 'Your personal cellar'}</Text><Text style={s.heroTitle}>A private catalog for bottles worth cellaring.</Text><View style={s.heroMetrics}><Metric label="In cellar" value={ownedWines.length} /><Metric label="Drink now" value={drinkNowCount} /><Metric label="Value" value={formatCurrency(cellarValue)} /></View><Text style={s.status}><Sparkles size={14} color="#681a2f" /> {status}</Text></View></Animated.View>;
  const collectionHeader = <>{heroBlock}<View style={[s.panel, s.collectionPanel]}>{!wines.length && <EmptyState camera={() => pickImage('camera')} library={() => pickImage('library')} samples={addSamples} />}<View style={s.sectionHead}><View><Text style={s.eyebrow}>Collection</Text><Text style={s.h2}>{filter === 'consumed' ? `${filtered.length} consumed` : filter === 'cellar' ? `${filtered.length} in cellar` : filter === 'all' ? `${filtered.length} cellar + history` : `${filtered.length} bottles`}</Text></View><View style={s.toggle}><IconButton active={layout === 'grid'} onPress={() => setViewPreference('grid')} icon={<Grid2X2 size={16} color={layout === 'grid' ? '#fffaf2' : '#756961'} />} /><IconButton active={layout === 'list'} onPress={() => setViewPreference('list')} icon={<List size={16} color={layout === 'list' ? '#fffaf2' : '#756961'} />} /></View></View><View style={s.search}><Search size={18} color="#756961" /><TextInput value={query} onChangeText={setQuery} placeholder="search producer, grape, country, region" style={s.searchInput} returnKeyType="search" /></View><ScrollView horizontal showsHorizontalScrollIndicator={false} keyboardShouldPersistTaps="handled" style={s.chipRow}>{collectionFilters.map((item) => <Chip key={item} label={chipLabel(item)} active={filter === item} onPress={() => setFilter(item)} />)}</ScrollView></View></>;
  const scrollContent = <ScrollView showsVerticalScrollIndicator={false} keyboardShouldPersistTaps="handled" keyboardDismissMode="on-drag" removeClippedSubviews contentContainerStyle={s.content}>{heroBlock}<Animated.View style={{ opacity: fade, transform: [{ translateY: rise }] }}>{tab === 'discover' && <DiscoverPanel query={discoverQuery} setQuery={setDiscoverQuery} results={discoverResults} search={runDiscoverSearch} save={saveWishlist} busy={busy} wishlistCount={wines.filter((wine) => wine.status === 'wishlist').length} layout={discoverLayout} setLayout={setViewPreference} />}{tab === 'add' && <WineEditor title="Add bottle" wine={draft} setWine={setDraft} save={saveWine} camera={() => pickImage('camera')} library={() => pickImage('library')} />}{tab === 'detail' && selected && <WineEditor title="Bottle detail" wine={selected} setWine={(next) => updateWine(next)} save={() => setTab('collection')} deleteWine={() => deleteWine(selected.id)} />}{tab === 'settings' && <SettingsScreen layout={layout} setLayout={setViewPreference} exportJson={exportJson} importJson={importJson} replayOnboarding={() => setShowOnboarding(true)} addSamples={addSamples} clearDevice={() => Alert.alert('Clear everything?', 'This deletes every bottle on this device.', [{ text: 'Cancel', style: 'cancel' }, { text: 'Clear', style: 'destructive', onPress: () => setWines([]) }])} bottleCount={ownedWines.length} wishlistCount={wines.filter((wine) => wine.status === 'wishlist').length} wines={ownedWines} consumedWines={consumedWines} insights={insights} cellarValue={cellarValue} drinkNowCount={drinkNowCount} auth={auth} syncState={syncState} syncMessage={syncMessage} lastSyncAt={lastSyncAt} busy={busy} login={(email, password) => handleAuth('login', email, password)} signup={(email, password, displayName) => handleAuth('signup', email, password, displayName)} logout={logout} syncNow={() => syncCellar('manual')} /> }</Animated.View></ScrollView>;

  return <SafeAreaView style={s.safe}><StatusBar barStyle="dark-content" /><KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : undefined} style={s.shell}><Onboarding visible={showOnboarding} profile={profile} finish={async (next) => { setProfile(next); await AsyncStorage.multiSet([[STORAGE_PROFILE, JSON.stringify(next)], [STORAGE_ONBOARDED, 'yes']]); setShowOnboarding(false); setTab('add'); }} />
    <View style={s.topbar}><Pressable style={s.brand} onPress={() => setTab('collection')}><View style={s.brandMark}><WineIcon color="#fffaf2" size={20} /></View><Text style={s.brandText}>Cellar</Text></Pressable><Text style={s.topHint}>Private cellar</Text></View>
    {tab === 'collection' ? <FlatList key={layout} data={displayWines} keyExtractor={(wine) => wine.id} numColumns={layout === 'grid' ? 2 : 1} ListHeaderComponent={collectionHeader} ListFooterComponent={ownedWines.length > 0 && filtered.length === 0 ? <SearchEmpty clear={() => { setQuery(''); setFilter('all'); }} /> : null} renderItem={renderWineItem} contentContainerStyle={s.content} columnWrapperStyle={layout === 'grid' ? s.gridRow : undefined} showsVerticalScrollIndicator={false} keyboardShouldPersistTaps="handled" keyboardDismissMode="on-drag" initialNumToRender={8} maxToRenderPerBatch={6} windowSize={7} removeClippedSubviews updateCellsBatchingPeriod={60} /> : scrollContent}
    <View style={s.nav}><Nav active={tab === 'collection'} icon={<Home />} label="Cellar" onPress={() => setTab('collection')} /><Nav active={tab === 'discover'} icon={<Search />} label="Discover" onPress={() => setTab('discover')} /><Nav active={tab === 'add'} icon={<Camera />} label="Add" onPress={() => pickImage('camera')} /><Nav active={tab === 'settings'} icon={<BarChart3 />} label="More" onPress={() => setTab('settings')} /></View></KeyboardAvoidingView></SafeAreaView>;
}

function Onboarding({ visible, profile, finish }: { visible: boolean; profile: Profile; finish: (profile: Profile) => void }) {
  const [local, setLocal] = useState(profile);
  const [step, setStep] = useState(0);
  const toggleStyle = (style: string) => setLocal((current) => ({ ...current, favoriteStyles: current.favoriteStyles.includes(style) ? current.favoriteStyles.filter((item) => item !== style) : [...current.favoriteStyles, style] }));
  return <Modal visible={visible} animationType="slide"><SafeAreaView style={s.modal}><ScrollView keyboardShouldPersistTaps="handled" keyboardDismissMode="on-drag" contentContainerStyle={s.onScroll}><View style={s.onCard}><View style={s.progressTrack}><View style={[s.progressFill, { width: `${((step + 1) / 4) * 100}%` }]} /></View>{step === 0 && <View style={s.onStep}><View style={s.onSeal}><ShieldCheck color="#fffaf2" size={30} /></View><Text style={s.eyebrow}>Age verification</Text><Text style={s.onTitle}>Confirm you are 21 or older.</Text><Text style={s.copy}>Cellar is intended for adults of legal drinking age. Please confirm before continuing to the app.</Text><View style={s.ageNotice}><Text style={s.ageNumber}>21+</Text><Text style={s.copy}>By continuing, you confirm that you are at least 21 years old.</Text></View></View>}{step === 1 && <View style={s.onStep}><View style={s.onSeal}><WineIcon color="#fffaf2" size={30} /></View><Text style={s.eyebrow}>Private cellar</Text><Text style={s.onTitle}>An elegant record for every bottle, vintage, and occasion.</Text><Text style={s.copy}>Scan labels, preserve tasting notes, track value, and build a refined map of your collection.</Text><View style={s.featureGrid}><Feature icon={<Camera color="#681a2f" size={20} />} title="Capture" copy="Camera or photo library, with OCR in native builds." /><Feature icon={<Star color="#681a2f" size={20} />} title="Taste" copy="Ratings, notes, tags, and bottle status." /><Feature icon={<ShieldCheck color="#681a2f" size={20} />} title="Private" copy="Local-first storage. No account required." /></View></View>}{step === 2 && <View style={s.onStep}><Text style={s.eyebrow}>Personalize</Text><Text style={s.onTitle}>Tailor the cellar to your collection.</Text><TextInput style={s.input} value={local.name} onChangeText={(name) => setLocal({ ...local, name })} placeholder="Your name" autoFocus /><Text style={s.label}>Wine comfort</Text><View style={s.wrap}>{['curious', 'regular', 'collector', 'pro'].map((experience) => <Chip key={experience} label={experience} active={local.experience === experience} onPress={() => setLocal({ ...local, experience })} />)}</View></View>}{step === 3 && <View style={s.onStep}><Text style={s.eyebrow}>Taste profile</Text><Text style={s.onTitle}>Define your house style.</Text><Text style={s.copy}>Choose the styles that anchor your collection.</Text><View style={s.wrap}>{styles.filter((x) => x !== 'unknown').map((style) => <Chip key={style} label={style} active={local.favoriteStyles.includes(style)} onPress={() => toggleStyle(style)} />)}</View></View>}<View style={s.onActions}>{step > 0 && <Pill label="Back" onPress={() => setStep((value) => value - 1)} />}{step < 3 ? <Pill dark label={step === 0 ? 'I am 21 or older' : 'Continue'} onPress={() => setStep((value) => value + 1)} /> : <Pill dark label="Start my cellar" icon={<WineIcon size={16} color="#fffaf2" />} onPress={() => finish({ ...local, name: local.name.trim() || 'My' })} />}</View></View></ScrollView></SafeAreaView></Modal>;
}

function Feature({ icon, title, copy }: { icon: React.ReactNode; title: string; copy: string }) { return <View style={s.feature}><View style={s.featureIcon}>{icon}</View><Text style={s.featureTitle}>{title}</Text><Text style={s.featureCopy}>{copy}</Text></View>; }
function ChoiceField({ label, value, options, onChange }: { label: string; value: string; options: string[]; onChange: (value: string) => void }) { return <View><Text style={s.label}>{label}</Text><View style={s.wrap}>{options.map((option) => <Chip key={option} label={option} active={value === option} onPress={() => onChange(option)} />)}</View></View>; }
function RatingPicker({ value, onChange }: { value: number; onChange: (value: number) => void }) { return <View><Text style={s.label}>Rating {value ? `${value}/5` : '—'}</Text><View style={s.stars}>{[1, 2, 3, 4, 5].map((n) => <Pressable key={n} onPress={() => onChange(n)}><Star size={30} fill={value >= n ? '#b88a3b' : 'transparent'} color="#b88a3b" /></Pressable>)}</View></View>; }
function WineEditor({ title, wine, setWine, save, camera, library, deleteWine }: { title: string; wine: Wine; setWine: (wine: Wine) => void; save: () => void; camera?: () => void; library?: () => void; deleteWine?: () => void }) { const isAdd = title === 'Add bottle'; const windowWine = withAutoDrinkWindow(wine); const window = drinkingWindow(windowWine); const pairings = wine.foodPairings ? wine.foodPairings.split(',').map((x) => x.trim()).filter(Boolean) : pairingFor(windowWine); return <View style={s.panel}><Text style={s.eyebrow}>{isAdd ? 'Add wine' : title}</Text>{isAdd && <View style={s.emptySteps}><View style={s.stepRow}><Text style={s.stepNum}>i.</Text><Text style={s.stepText}>Scan or upload the label</Text></View><View style={s.stepRow}><Text style={s.stepNum}>ii.</Text><Text style={s.stepText}>Confirm the database match</Text></View><View style={s.stepRow}><Text style={s.stepNum}>iii.</Text><Text style={s.stepText}>Save to current inventory</Text></View></View>}{wine.photo ? <Image source={{ uri: wine.photo }} style={s.photo} fadeDuration={0} /> : <View style={s.photoEmpty}><WineIcon color="#681a2f" size={44} /><Text style={s.copy}>{isAdd ? 'Scan a bottle from Add, or upload a saved label photo here.' : 'Add a label photo from your library.'}</Text>{library && <Pill label="Photos" icon={<Upload size={16} color="#2a211e" />} onPress={library} />}</View>}<View style={s.sommCard}><Text style={s.eyebrow}>{isAdd ? 'Auto-filled cellar profile' : 'Sommelier note'}</Text><Text style={s.sommTitle}>{isAdd ? 'Confirm before saving' : window.label}</Text><Text style={s.copy}>{isAdd ? 'These fields are for identity, origin, value, and drinking window. Personal ratings and tasting notes appear after the bottle is marked consumed.' : sommelierNote(windowWine)}</Text>{!isAdd && <View style={s.wrap}>{pairings.map((pairing) => <View key={pairing} style={s.pairingPill}><Text style={s.pairingText}>{pairing}</Text></View>)}</View>}</View><Field label="Wine name" value={wine.wineName} onChangeText={(wineName) => setWine({ ...wine, wineName })} /><Field label="Producer" value={wine.producer} onChangeText={(producer) => setWine({ ...wine, producer })} /><Field label="Vintage" value={wine.vintage} onChangeText={(vintage) => setWine(withAutoDrinkWindow({ ...wine, vintage }))} /><ChoiceField label="Region" value={wine.region} options={regionOptions} onChange={(region) => setWine(withAutoDrinkWindow({ ...wine, region }))} /><OriginPanel wine={wine} /><ChoiceField label="Country" value={wine.country} options={countryOptions} onChange={(country) => setWine({ ...wine, country })} /><Field label="Sub-region" value={wine.subRegion} onChangeText={(subRegion) => setWine({ ...wine, subRegion })} /><Field label="Appellation" value={wine.appellation} onChangeText={(appellation) => setWine({ ...wine, appellation })} /><ChoiceField label="Varietal" value={wine.varietal} options={varietalOptions} onChange={(varietal) => setWine(withAutoDrinkWindow({ ...wine, varietal }))} /><ChoiceField label="Wine type" value={wine.style} options={styles} onChange={(style) => setWine(withAutoDrinkWindow({ ...wine, style: style as WineStyle }))} /><ChoiceField label="Bottle size" value={wine.bottleSize} options={bottleSizeOptions} onChange={(bottleSize) => setWine({ ...wine, bottleSize })} />{!isAdd && <View style={s.wrap}>{(['cellar', 'consumed', 'wishlist'] as WineStatus[]).map((status) => <Chip key={status} label={chipLabel(status)} active={wine.status === status} onPress={() => setWine({ ...wine, status, dateConsumed: status === 'consumed' && !wine.dateConsumed ? new Date().toISOString().slice(0, 10) : wine.dateConsumed })} />)}</View>}{!isAdd && wine.status !== 'consumed' && <RatingPicker value={wine.rating} onChange={(rating) => setWine({ ...wine, rating })} />}{wine.status === 'consumed' && !isAdd && <><RatingPicker value={wine.rating} onChange={(rating) => setWine({ ...wine, rating })} /><Field label="Personal tasting notes" value={wine.notes} onChangeText={(notes) => setWine({ ...wine, notes })} multiline /><Field label="Date consumed" value={wine.dateConsumed} onChangeText={(dateConsumed) => setWine({ ...wine, dateConsumed })} /></>}<View style={s.valuePanel}><Text style={s.label}>Value tracking</Text><Text style={s.copy}>Market value is filled from the lookup when available. Price paid is what you actually spent.</Text><View style={s.two}><Field label="Price paid" value={wine.price} onChangeText={(price) => setWine({ ...wine, price })} /><Field label="Market value" value={wine.marketValue} onChangeText={(marketValue) => setWine({ ...wine, marketValue })} /></View></View><View style={s.two}><Field label="Critic score" value={wine.criticScore} onChangeText={(criticScore) => setWine({ ...wine, criticScore })} /><Field label="Data source" value={wine.dataSource} onChangeText={(dataSource) => setWine({ ...wine, dataSource })} /></View><Field label="Cellar location" value={wine.location} onChangeText={(location) => setWine({ ...wine, location })} /><View style={s.valuePanel}><Text style={s.label}>Drinking window</Text><Text style={s.copy}>Automatically calculated from the wine database when available, otherwise from vintage, varietal, region, and style. No manual entry needed.</Text><View style={s.stats}><Stat label="Drink from" value={windowWine.drinkStart || 'Add vintage'} /><Stat label="Drink by" value={windowWine.drinkEnd || 'Add vintage'} /></View><Text style={s.copy}>{window.detail}</Text></View>{!isAdd && <Field label="Food pairings" value={wine.foodPairings} onChangeText={(foodPairings) => setWine({ ...wine, foodPairings })} />}<Field label="Where bought / where to buy again" value={wine.purchaseSource} onChangeText={(purchaseSource) => setWine({ ...wine, purchaseSource })} /><Field label="Purchase date" value={wine.purchaseDate} onChangeText={(purchaseDate) => setWine({ ...wine, purchaseDate })} /><Field label="Tags" value={wine.tags} onChangeText={(tags) => setWine({ ...wine, tags })} /><Pill dark label={isAdd ? 'Save to cellar' : 'Done'} icon={<Star size={16} color="#fffaf2" />} onPress={save} />{deleteWine && <Pill label="Share tasting note" icon={<Upload size={16} color="#2a211e" />} onPress={() => Share.share({ message: `${wine.wineName || 'Untitled bottle'} ${wine.vintage ? `(${wine.vintage})` : ''}\n${wine.rating ? `${wine.rating}/5 stars` : 'Not rated yet'}\n${wine.notes || sommelierNote(wine)}` })} />}{deleteWine && <Pill danger label="Delete bottle" icon={<Trash2 size={16} color="#8a2020" />} onPress={deleteWine} />}</View>; }
function Field(props: { label: string; value: string; onChangeText: (value: string) => void; multiline?: boolean; secureTextEntry?: boolean }) { return <View><Text style={s.label}>{props.label}</Text><TextInput {...props} style={[s.input, props.multiline && s.textarea]} placeholder={props.label} returnKeyType={props.multiline ? 'default' : 'done'} blurOnSubmit={!props.multiline} autoCapitalize={props.label === 'Email' ? 'none' : undefined} keyboardType={props.label === 'Email' ? 'email-address' : 'default'} /> </View>; }
function EmptyState({ camera, library, samples }: { camera: () => void; library: () => void; samples: () => void }) { return <View style={s.empty}><View style={s.emptySeal}><WineIcon color="#fffaf2" size={28} /></View><Text style={s.h2}>Begin your collection.</Text><Text style={s.copy}>Start with a label scan, add a saved photo, or preview the cellar with a sample collection.</Text><View style={s.emptySteps}><View style={s.stepRow}><Text style={s.stepNum}>i.</Text><Text style={s.stepText}>Capture the label</Text></View><View style={s.stepRow}><Text style={s.stepNum}>ii.</Text><Text style={s.stepText}>Confirm the details</Text></View><View style={s.stepRow}><Text style={s.stepNum}>iii.</Text><Text style={s.stepText}>Record the tasting</Text></View></View><Pill dark label="Scan label" icon={<Camera size={16} color="#fffaf2" />} onPress={camera} /><Pill label="Upload photo" icon={<Upload size={16} color="#2a211e" />} onPress={library} /><Pill label="Add demo cellar" icon={<Sparkles size={16} color="#2a211e" />} onPress={samples} /></View>; }
function SearchEmpty({ clear }: { clear: () => void }) { return <View style={s.searchEmpty}><Search color="#681a2f" size={26} /><Text style={s.cardTitle}>No bottles found</Text><Text style={s.copy}>Refine the search or clear filters to view the full collection.</Text><Pill label="Clear search" onPress={clear} /></View>; }
function SettingsScreen({ layout, setLayout, exportJson, importJson, replayOnboarding, addSamples, clearDevice, bottleCount, wishlistCount, consumedWines, wines, insights, cellarValue, drinkNowCount, auth, syncState, syncMessage, lastSyncAt, busy, login, signup, logout, syncNow }: { layout: Layout; setLayout: (layout: Layout) => void; exportJson: () => void; importJson: () => Promise<void>; replayOnboarding: () => void; addSamples: () => void; clearDevice: () => void; bottleCount: number; wishlistCount: number; consumedWines: Wine[]; wines: Wine[]; insights: { average: number; varietals: [string, number][]; styles: [string, number][] }; cellarValue: number; drinkNowCount: number; auth: AuthSession | null; syncState: SyncState; syncMessage: string; lastSyncAt: string; busy: boolean; login: (email: string, password: string) => void; signup: (email: string, password: string, displayName?: string) => void; logout: () => void; syncNow: () => void }) { return <View style={s.panel}><Text style={s.eyebrow}>More</Text><Text style={s.h2}>Cellar pulse</Text><View style={s.stats}><Stat label="In cellar" value={bottleCount} /><Stat label="Average" value={insights.average ? insights.average.toFixed(1) : '—'} /></View><View style={s.stats}><Stat label="Cellar value" value={formatCurrency(cellarValue)} /><Stat label="Drink now" value={drinkNowCount} /></View><AuthPanel auth={auth} syncState={syncState} syncMessage={syncMessage} lastSyncAt={lastSyncAt} busy={busy} login={login} signup={signup} logout={logout} syncNow={syncNow} /><SommelierPanel wines={wines} /><Bars title="Varietals" entries={insights.varietals} /><Bars title="Style mix" entries={insights.styles} /><View style={s.settingsSection}><Text style={s.label}>View preference</Text><Text style={s.copy}>Choose the default browsing style for cellar and discovery search results.</Text><View style={s.preferenceRow}><Chip label="grid" active={layout === 'grid'} onPress={() => setLayout('grid')} /><Chip label="list" active={layout === 'list'} onPress={() => setLayout('list')} /></View></View><View style={s.settingsSection}><Text style={s.label}>Data and backup</Text><Text style={s.copy}>{bottleCount} bottles in cellar, {consumedWines.length} consumed, and {wishlistCount} wishlist bottles are stored on this device.</Text><Pill dark label="Export backup" icon={<Download size={16} color="#fffaf2" />} onPress={exportJson} /><Pill label="Import JSON" icon={<Upload size={16} color="#2a211e" />} onPress={() => importJson().catch((e: Error) => Alert.alert('Import failed', e.message))} /></View><View style={s.settingsSection}><Text style={s.label}>Cellar preferences</Text><Pill label="Replay onboarding" icon={<Home size={16} color="#2a211e" />} onPress={replayOnboarding} /><Pill label="Add demo cellar" icon={<Sparkles size={16} color="#2a211e" />} onPress={addSamples} /></View><View style={s.aboutCard}><Text style={s.eyebrow}>About</Text><Text style={s.sommTitle}>Cellar {APP_VERSION}</Text><Text style={s.copy}>A private, local-first wine catalog for scanning labels, tracking value, and knowing when to open the right bottle. OCR requires a native TestFlight or development build.</Text></View><Pill label="Clear device" danger icon={<Trash2 size={16} color="#8a2020" />} onPress={clearDevice} /></View>; }


function AuthPanel({ auth, syncState, syncMessage, lastSyncAt, busy, login, signup, logout, syncNow }: { auth: AuthSession | null; syncState: SyncState; syncMessage: string; lastSyncAt: string; busy: boolean; login: (email: string, password: string) => void; signup: (email: string, password: string, displayName?: string) => void; logout: () => void; syncNow: () => void }) {
  const [mode, setMode] = useState<'login' | 'signup'>('signup');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [displayName, setDisplayName] = useState('');
  const canSubmit = email.trim().includes('@') && password.length >= 8;
  const stateLabel: Record<SyncState, string> = { local: 'Local only', syncing: 'Syncing', synced: 'Backed up', offline: 'Offline safe', error: 'Needs attention' };

  if (auth) return <View style={s.syncCard}><View style={s.syncHeader}><View><Text style={s.eyebrow}>Cloud cellar</Text><Text style={s.sommTitle}>{stateLabel[syncState]}</Text></View><View style={[s.syncDot, syncState === 'synced' && s.syncDotGood, syncState === 'syncing' && s.syncDotBusy, (syncState === 'offline' || syncState === 'error') && s.syncDotWarn]} /></View><Text style={s.copy}>Signed in as {auth.user.email}. {syncMessage}</Text>{lastSyncAt ? <Text style={s.syncMeta}>Last sync {lastSyncAt}</Text> : null}<Pill dark disabled={busy || syncState === 'syncing'} label={syncState === 'syncing' ? 'Syncing' : 'Sync now'} icon={<ShieldCheck size={16} color="#fffaf2" />} onPress={syncNow} /><Pill label="Sign out" onPress={logout} /></View>;

  return <View style={s.syncCard}><Text style={s.eyebrow}>Optional account</Text><Text style={s.sommTitle}>Keep it local, or turn on backup.</Text><Text style={s.copy}>Cellar works without an account. Sign up only if you want encrypted token auth, cloud backup, and multi-device sync when online.</Text><View style={s.preferenceRow}><Chip label="Create account" active={mode === 'signup'} onPress={() => setMode('signup')} /><Chip label="Log in" active={mode === 'login'} onPress={() => setMode('login')} /></View>{mode === 'signup' && <Field label="Display name" value={displayName} onChangeText={setDisplayName} />}<Field label="Email" value={email} onChangeText={setEmail} /><Field label="Password" value={password} onChangeText={setPassword} secureTextEntry /><Text style={s.syncMeta}>Use at least 8 characters. Tokens are stored in the device secure store.</Text><Pill dark disabled={!canSubmit || busy} label={busy ? 'Please wait' : mode === 'signup' ? 'Create backup account' : 'Log in and sync'} icon={<ShieldCheck size={16} color="#fffaf2" />} onPress={() => mode === 'signup' ? signup(email, password, displayName.trim() || undefined) : login(email, password)} /><Text style={s.copy}>{syncMessage}</Text></View>;
}

function DiscoverPanel({ query, setQuery, results, search, save, busy, wishlistCount, layout, setLayout }: { query: string; setQuery: (value: string) => void; results: Wine[]; search: () => void; save: (wine: Wine) => void; busy: boolean; wishlistCount: number; layout: Layout; setLayout: (layout: Layout) => void }) { return <View style={s.panel}><Text style={s.eyebrow}>Discover</Text><Text style={s.h2}>Find bottles before they enter your cellar.</Text><Text style={s.copy}>Search the wine database for bottles to try, then save interesting finds to a wishlist separate from owned inventory.</Text><View style={s.discoverHero}><Text style={s.sommTitle}>{wishlistCount ? `${wishlistCount} wishlist bottles` : 'Wishlist cellar'}</Text><Text style={s.copy}>Saved discoveries appear under the wishlist filter, but they stay out of your cellar count and location workflow until you buy them.</Text></View><View style={s.search}><Search size={18} color="#756961" /><TextInput value={query} onChangeText={setQuery} placeholder="search producer, region, grape, vintage" style={s.searchInput} returnKeyType="search" onSubmitEditing={search} /></View><View style={s.resultTools}><Pill dark disabled={busy || !query.trim()} label={busy ? 'Searching' : 'Search wines'} icon={<Search size={16} color="#fffaf2" />} onPress={search} /><View style={s.toggle}><IconButton active={layout === 'grid'} onPress={() => setLayout('grid')} icon={<Grid2X2 size={16} color={layout === 'grid' ? '#fffaf2' : '#756961'} />} /><IconButton active={layout === 'list'} onPress={() => setLayout('list')} icon={<List size={16} color={layout === 'list' ? '#fffaf2' : '#756961'} />} /></View></View>{results.length === 0 ? <View style={s.searchEmpty}><Search color="#681a2f" size={26} /><Text style={s.cardTitle}>No discovery search yet</Text><Text style={s.copy}>Try “Barolo 2019”, “Napa Cabernet”, or “grower Champagne”.</Text></View> : <View style={layout === 'grid' ? s.discoverGrid : s.list}>{results.map((wine) => <View key={wine.id} style={layout === 'grid' ? s.discoverGridCard : s.discoverCard}><WineCard wine={wine} layout={layout} fullWidth onOpen={() => {}} /><Pill label="Save to wishlist" icon={<Star size={16} color="#2a211e" />} onPress={() => save(wine)} /></View>)}</View>}</View>; }
function OriginPanel({ wine }: { wine: Wine }) { return <View style={s.originPanel}><View style={s.originMark}><Text style={s.originMarkText}>{countryCode(wine.country)}</Text></View><View style={s.originTextBlock}><Text style={s.originCountry}>{wine.country || 'Origin pending'}</Text><Text style={s.originTrail}>{originSummary(wine) || 'Country, region, and appellation will appear here after lookup.'}</Text></View></View>; }
const WineCard = memo(function WineCard({ wine, layout, onOpen, fullWidth }: { wine: Wine; layout: Layout; onOpen: (id: string) => void; fullWidth?: boolean }) { const compact = layout === 'grid'; return <Pressable onPress={() => onOpen(wine.id)} style={[s.card, layout === 'list' && s.cardList, fullWidth && s.cardFull]}>{wine.photo ? <Image source={{ uri: wine.photo }} style={layout === 'list' ? s.thumbSmall : s.thumb} fadeDuration={0} /> : <View style={layout === 'list' ? s.thumbSmall : s.thumb}><WineIcon color="#681a2f" /></View>}{compact && <View style={s.cardShade} />}{wine.rating > 0 && <View style={s.ratingBadge}><Text style={s.ratingBadgeText}>{wine.rating}/5</Text></View>}<View style={[s.cardBody, compact && s.cardOverlay]}><Text style={[s.meta, compact && s.cardMetaLight]}>{wine.vintage || 'NV'}</Text><Text style={[s.cardTitle, compact && s.cardTitleLight]} numberOfLines={compact ? 2 : 2}>{wine.wineName || 'Untitled bottle'}</Text></View></Pressable>; });
function SommelierPanel({ wines }: { wines: Wine[] }) { const drinkNow = wines.find((wine) => wine.status === 'cellar' && drinkingWindow(wine).label === 'Drink now'); const favorite = [...wines].filter((wine) => wine.status === 'cellar').sort((a, b) => b.rating - a.rating)[0]; const pick = drinkNow || favorite; return <View style={s.sommCard}><Text style={s.eyebrow}>Cellar advisor</Text><Text style={s.sommTitle}>{pick ? `Open ${pick.wineName || 'a bottle'} next` : 'Add bottles for cellar guidance'}</Text><Text style={s.copy}>{pick ? sommelierNote(pick) : 'Cellar will translate your collection into drinking windows, pairing ideas, and buy-again notes.'}</Text></View>; }
function Bars({ title, entries }: { title: string; entries: [string, number][] }) { const max = Math.max(1, ...entries.map(([, value]) => value)); return <View style={s.bars}><Text style={s.label}>{title}</Text>{entries.length ? entries.map(([name, value]) => <View key={name} style={s.bar}><View style={[s.barFill, { width: `${(value / max) * 100}%` }]} /><Text style={s.barText}>{name || 'Unknown'}</Text><Text style={s.barText}>{value}</Text></View>) : <Text style={s.copy}>No data yet.</Text>}</View>; }
function Stat({ label, value }: { label: string; value: string | number }) { return <View style={s.stat}><Text style={s.copy}>{label}</Text><Text style={s.statValue}>{value}</Text></View>; }
function Metric({ label, value }: { label: string; value: string | number }) { return <View style={s.metric}><Text style={s.metricValue}>{value}</Text><Text style={s.metricLabel}>{label}</Text></View>; }
function Pill({ label, icon, onPress, dark, danger, disabled }: { label: string; icon?: React.ReactNode; onPress: () => void; dark?: boolean; danger?: boolean; disabled?: boolean }) { return <Pressable disabled={disabled} style={[s.pill, dark && s.pillDark, danger && s.pillDanger, disabled && s.disabled]} onPress={() => { Haptics.selectionAsync(); onPress(); }}>{icon}<Text style={[s.pillText, dark && s.pillTextDark, danger && s.pillTextDanger]}>{label}</Text></Pressable>; }
function Chip({ label, active, onPress }: { label: string; active: boolean; onPress: () => void }) { return <Pressable style={[s.chip, active && s.chipActive]} onPress={() => { Haptics.selectionAsync(); onPress(); }}><Text style={[s.chipText, active && s.chipTextActive]}>{label}</Text></Pressable>; }
function IconButton({ active, onPress, icon }: { active: boolean; onPress: () => void; icon: React.ReactNode }) { return <Pressable style={[s.iconButton, active && s.iconActive]} onPress={onPress}>{icon}</Pressable>; }
function Nav({ active, icon, label, onPress }: { active: boolean; icon: React.ReactElement<{ color?: string; size?: number; strokeWidth?: number }>; label: string; onPress: () => void }) { const color = active ? '#fffaf2' : 'rgba(255,250,242,.55)'; return <Pressable style={[s.navItem, active && s.navActive]} onPress={() => { Haptics.selectionAsync(); onPress(); }}>{React.cloneElement(icon, { color, size: 18, strokeWidth: 1.6 })}<Text style={[s.navText, active && s.navTextActive]}>{label}</Text></Pressable>; }

